<script>
  const buttonContainer = document.getElementById('buttonContainer');

  const metaDataRaw = localStorage.getItem('examMetaData');
  const metaData = JSON.parse(metaDataRaw);
  const batches = metaData.SectionTotalQuestion; // Each batch has this many buttons
  const allBatchDivs = [];
  let buttonIndex = 1;

  batches.forEach((count, batchIndex) => {
    const batchDiv = document.createElement('div');

    // ✅ Apply grid styles to the batch container
    batchDiv.className = 'grid grid-cols-5 gap-1 text-lg';
    batchDiv.style.display = 'none'; // hide initially

    for (let i = 0; i < count; i++) {
      const button = document.createElement('button');

      // ✅ Keep original button styling untouched
      button.className = "question-btn rounded w-10 h-10 text-base bg-no-repeat bg-center bg-cover";
      button.setAttribute("data-question", buttonIndex);
      button.setAttribute("title", "Not Visited");
      button.setAttribute("style", "background-image: url('../../assets/images/Logo1.png');");
      button.setAttribute("onclick", `updateQuestionButtonStatus(${buttonIndex})`);
      button.textContent = buttonIndex;

      batchDiv.appendChild(button);
      buttonIndex++;
    }

    allBatchDivs.push(batchDiv);
    buttonContainer.appendChild(batchDiv);
  });

  // ✅ Function to show a specific batch (1-based index)
  function showBatch(batchNo) {
    allBatchDivs.forEach((batch, idx) => {
      batch.style.display =  'grid' ;
    });
  }

  // ✅ Show the first batch by default
  showBatch(1);


</script>


